func:
flow.set('sheet3CurrentState', msg.payload);
node.status({ fill: 'grey', shape: 'ring', text: 'latest state 저장' });
return null;

const currentState = flow.get('sheet3CurrentState') || null;
const ruleResult = msg.payload || null;
const analystPersona = 'field-risk-early-analyst';

if (!currentState || !ruleResult) {
  node.status({ fill: 'grey', shape: 'ring', text: 'state/rule 대기중' });
  return null;
}

const userId = currentState.userId || ruleResult.userId || 'unknown';
const roomId = currentState.roomId || ruleResult.roomId || 'room-01';
const llmRequest = {
  analystPersona,
  systemPrompt: [
    '당신은 스마트팩토리의 현장 위험 조기 해석 담당자입니다.',
    '당신의 역할은 state/current와 rule/result를 함께 읽고, 룰 엔진보다 더 앞단의 위험 징후를 사람이 이해하기 쉬운 메시지로 정리하는 것입니다.',
    '당신은 제어 명령을 직접 내리지 않습니다. 현장 전문가 의견 메시지를 생성하세요.',
    'overheatMode=on, 급격한 온도 상승, 진동 변화, 에어컨 꺼짐 상태, 룰 엔진 warning/critical 진입 여부를 함께 고려하세요.'
  ].join(' '),
  answerFormatGuide: {
    instruction: '현장 전문가 의견 메시지를 중심으로 답하고, 가능하면 message 필드를 포함한 JSON object로 답하세요.'
  },
  userPrompt: JSON.stringify({
    task: '현장 위험 조기 해석 메시지 작성',
    stateCurrent: currentState,
    ruleResult
  }, null, 2),
  options: {
    temperature: 0.2
  }
};

msg.topic = `kiot/${userId}/dt/factory/${roomId}/analysis/field-analyst/_llm-request`;
msg.payload = {
  llmRequest,
  analysisInput: {
    stateCurrent: currentState,
    ruleResult
  }
};
node.status({ fill: 'blue', shape: 'dot', text: '요청 생성 완료' });
return msg;

const analysisInput = msg.payload?.analysisInput || {};
const currentState = analysisInput.stateCurrent || {};
const ruleResult = analysisInput.ruleResult || {};
const temperature = currentState.sensors?.temperature?.value ?? null;
const conveyorOverheatMode = currentState.actuators?.conveyorBelt?.overheatMode ?? null;
const airconPower = currentState.actuators?.aircon?.power ?? null;
const ruleRiskLevel = ruleResult.riskLevel || 'unknown';

let message = '현장은 안정 범위로 보이며 현재 즉시 추가 조치는 필요하지 않습니다.';
if (conveyorOverheatMode === 'on' && typeof temperature === 'number' && temperature >= 25 && temperature < 35) {
  message = '과열 모드가 활성화된 상태에서 온도가 빠르게 상승 중입니다. 아직 룰 엔진 경고 구간은 아니지만 조기 대응을 준비해야 합니다.';
}
if (ruleRiskLevel === 'warning' || (typeof temperature === 'number' && temperature >= 35)) {
  message = '온도가 경고 구간에 진입했습니다. 냉각 동작 여부와 온도 상승 추세를 집중 관찰해야 합니다.';
}
if (ruleRiskLevel === 'critical' || (typeof temperature === 'number' && temperature >= 40)) {
  message = '임계 온도에 근접하고 있습니다. 장비 보호 관점에서 관리자 판단과 선제 대응을 서둘러야 합니다.';
}
if (airconPower === 'off' && typeof temperature === 'number' && temperature >= 30) {
  message += ' 현재 에어컨이 꺼져 있으므로 냉각 시점을 앞당길 필요가 있습니다.';
}

msg.payload = {
  llmProvider: 'gemini-mock',
  llmResponse: {
    message
  }
};
return msg;

const originalPayload = msg.payload || {};
const llmRequest = originalPayload.llmRequest || {};
const analysisInput = originalPayload.analysisInput || {};
const apiKey = env.get('GEMINI_API_KEY');
const model = env.get('GEMINI_API_MODEL') || 'gemini-flash-latest';
const endpoint = env.get('GEMINI_API_ENDPOINT') || `https://generativelanguage.googleapis.com/v1beta/models/${model}:generateContent`;

if (!apiKey) {
  node.error('GEMINI_API_KEY 환경변수가 없습니다. Node-RED 실행 전에 export GEMINI_API_KEY를 설정하세요.', msg);
  node.status({ fill: 'red', shape: 'ring', text: 'GEMINI_API_KEY 없음' });
  return null;
}

const systemPrompt = llmRequest.systemPrompt || '당신은 스마트팩토리의 현장 위험 조기 해석 담당자입니다.';
const answerGuide = llmRequest.answerFormatGuide?.instruction || '현장 전문가 의견 메시지를 한국어로 간결하게 작성하세요.';
const userPrompt = llmRequest.userPrompt || JSON.stringify(analysisInput, null, 2);

msg.method = 'POST';
msg.url = endpoint;
msg.headers = {
  'Content-Type': 'application/json',
  'X-goog-api-key': apiKey
};
msg.payload = {
  systemInstruction: {
    parts: [{ text: systemPrompt }]
  },
  contents: [
    {
      role: 'user',
      parts: [
        {
          text: `${answerGuide}\n\n${userPrompt}`
        }
      ]
    }
  ],
  generationConfig: {
    temperature: llmRequest.options?.temperature ?? 0.2
  }
};
msg.llmProvider = 'gemini-api';
msg.analysisInput = analysisInput;
node.status({ fill: 'blue', shape: 'dot', text: 'Gemini 요청 준비 완료' });
return msg;

const payload = msg.payload || {};

if (msg.statusCode && (msg.statusCode < 200 || msg.statusCode >= 300)) {
  const errorMessage = payload.error?.message || `HTTP ${msg.statusCode}`;
  node.error(`Gemini API 호출 실패: ${errorMessage}`, msg);
  node.status({ fill: 'red', shape: 'ring', text: `Gemini 실패 ${msg.statusCode}` });
  return null;
}

function stripCodeFence(text) {
  const trimmed = String(text || '').trim();
  const matched = trimmed.match(/^```(?:json)?\s*([\s\S]*?)\s*```$/);
  return matched ? matched[1].trim() : trimmed;
}

function firstGeminiText(response) {
  const parts = response?.candidates?.[0]?.content?.parts || [];
  const textPart = parts.find(part => typeof part.text === 'string');
  return textPart?.text || null;
}

let message = null;
if (typeof payload.llmResponse === 'string') {
  message = payload.llmResponse;
} else if (payload.llmResponse && typeof payload.llmResponse.message === 'string') {
  message = payload.llmResponse.message;
} else if (typeof payload.content === 'string') {
  message = payload.content;
} else {
  const geminiText = firstGeminiText(payload);
  if (geminiText) {
    const stripped = stripCodeFence(geminiText);
    try {
      const parsed = JSON.parse(stripped);
      message = typeof parsed.message === 'string' ? parsed.message : stripped;
    } catch (error) {
      message = stripped;
    }
  }
}

if (!message) {
  node.status({ fill: 'red', shape: 'ring', text: 'LLM 메시지 추출 실패' });
  return null;
}

const requestSource = flow.get('sheet3CurrentState') || {};
const userId = requestSource.userId || 'unknown';
const roomId = requestSource.roomId || 'room-01';
msg.topic = `kiot/${userId}/dt/factory/${roomId}/analysis/field-analyst`;
msg.payload = {
  userId,
  roomId,
  generatedAt: new Date().toISOString(),
  analystPersona: 'field-risk-early-analyst',
  llmProvider: msg.llmProvider || payload.llmProvider || 'unknown',
  message
};
node.status({ fill: 'green', shape: 'dot', text: '메시지 발행 준비 완료' });
return msg;
